changeSet.sql:
DECLARE @q2Id BIGINT, @q4Id BIGINT;

SELECT @q2Id = id FROM question WHERE prompt = 'True or False: A primary key can contain NULL values.';
SELECT @q4Id = id FROM question WHERE prompt = 'Which normal form ensures there are no transitive dependencies?';

INSERT INTO answer_option (question_id, content, is_correct)
VALUES
    (@q2Id, 'True', 0),
    (@q2Id, 'False', 1);

INSERT INTO answer_option (question_id, content, is_correct)
VALUES
    (@q4Id, 'First Normal Form (1NF)', 0),
    (@q4Id, 'Second Normal Form (2NF)', 0),
    (@q4Id, 'Third Normal Form (3NF)', 1),
    (@q4Id, 'Boyce-Codd Normal Form (BCNF)', 0);
